prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elem ?name ?type WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1f1b01e0a85340689b6df314b32bb4b6" ;
         tai:belongsTo ?org .
  ?choreo tai:belongsTo ?model .
  ?elem tai:belongsTo ?choreo .
  ?elem bbo:name ?name .
  FILTER(STRLEN(STR(?name)) > 0)
  OPTIONAL { ?elem a ?type . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?type (COUNT(*) AS ?count) (SUM(IF(BOUND(?n),1,0)) AS ?withNameCount) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1f1b01e0a85340689b6df314b32bb4b6" ;
         tai:belongsTo ?org .
  ?choreo tai:belongsTo ?model .

  ?elem tai:belongsTo ?choreo ;
        a ?type .
  OPTIONAL { ?elem bbo:name ?n . }
}
GROUP BY ?type
ORDER BY DESC(?count)
LIMIT 25

